type connectionWhere[Q psql.Filterable] struct {
	ID        psql.WhereMod[Q, int32]
	Name      psql.WhereMod[Q, string]
	Kind      psql.WhereMod[Q, string]
	DSN       psql.WhereNullMod[Q, string]
	IsEnabled psql.WhereMod[Q, bool]
	UserID    psql.WhereMod[Q, int32]
	CreatedAt psql.WhereMod[Q, time.Time]
	Metadata  psql.WhereMod[Q, types.JSON[json.RawMessage]]
}

func (connectionWhere[Q]) AliasedAs(alias string) connectionWhere[Q] {
	return buildConnectionWhere[Q](buildConnectionColumns(alias))
}

func buildConnectionWhere[Q psql.Filterable](cols connectionColumns) connectionWhere[Q] {
	return connectionWhere[Q]{
		ID:        psql.Where[Q, int32](cols.ID.Expression),
		Name:      psql.Where[Q, string](cols.Name.Expression),
		Kind:      psql.Where[Q, string](cols.Kind.Expression),
		DSN:       psql.WhereNull[Q, string](cols.DSN.Expression),
		IsEnabled: psql.Where[Q, bool](cols.IsEnabled.Expression),
		UserID:    psql.Where[Q, int32](cols.UserID.Expression),
		CreatedAt: psql.Where[Q, time.Time](cols.CreatedAt.Expression),
		Metadata:  psql.Where[Q, types.JSON[json.RawMessage]](cols.Metadata.Expression),
	}
}

func (o *Connection) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "ChatConversations":
		rels, ok := retrieved.(ChatConversationSlice)
		if !ok {
			return fmt.Errorf("connection cannot load %T as %q", retrieved, name)
		}

		o.R.ChatConversations = rels
		o.R.Loaded.ChatConversations = true

		return nil
	case "ChatMessageExecutions":
		rels, ok := retrieved.(ChatMessageExecutionSlice)
		if !ok {
			return fmt.Errorf("connection cannot load %T as %q", retrieved, name)
		}

		o.R.ChatMessageExecutions = rels
		o.R.Loaded.ChatMessageExecutions = true

		return nil
	case "ConnectionAccesses":
		rels, ok := retrieved.(ConnectionAccessSlice)
		if !ok {
			return fmt.Errorf("connection cannot load %T as %q", retrieved, name)
		}

		o.R.ConnectionAccesses = rels
		o.R.Loaded.ConnectionAccesses = true

		return nil
	case "User":
		rel, ok := retrieved.(*User)
		if !ok {
			return fmt.Errorf("connection cannot load %T as %q", retrieved, name)
		}

		o.R.User = rel
		o.R.Loaded.User = true

		return nil
	case "SchemaChunks":
		rels, ok := retrieved.(SchemaChunkSlice)
		if !ok {
			return fmt.Errorf("connection cannot load %T as %q", retrieved, name)
		}

		o.R.SchemaChunks = rels
		o.R.Loaded.SchemaChunks = true

		return nil
	case "SchemaSnapshots":
		rels, ok := retrieved.(SchemaSnapshotSlice)
		if !ok {
			return fmt.Errorf("connection cannot load %T as %q", retrieved, name)
		}

		o.R.SchemaSnapshots = rels
		o.R.Loaded.SchemaSnapshots = true

		return nil
	default:
		return fmt.Errorf("connection has no relationship %q", name)
	}
}

type connectionPreloader struct {
	User func(...psql.PreloadOption) psql.Preloader
}

func buildConnectionPreloader() connectionPreloader {
	return connectionPreloader{
		User: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*User, UserSlice](psql.PreloadRel{
				Name: "User",
				Sides: []psql.PreloadSide{
					{
						From:        Connections,
						To:          Users,
						FromColumns: []string{"user_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Users.Columns.Names(), opts...)
		},
	}
}

