type connectionCountThenLoader[Q orm.Loadable] struct {
	ChatConversations     func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	ChatMessageExecutions func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	ConnectionAccesses    func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	SchemaChunks          func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	SchemaSnapshots       func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildConnectionCountThenLoader[Q orm.Loadable]() connectionCountThenLoader[Q] {
	type ChatConversationsCountInterface interface {
		LoadCountChatConversations(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type ChatMessageExecutionsCountInterface interface {
		LoadCountChatMessageExecutions(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type ConnectionAccessesCountInterface interface {
		LoadCountConnectionAccesses(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type SchemaChunksCountInterface interface {
		LoadCountSchemaChunks(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type SchemaSnapshotsCountInterface interface {
		LoadCountSchemaSnapshots(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return connectionCountThenLoader[Q]{
		ChatConversations: countThenLoadBuilder[Q](
			"ChatConversations",
			func(ctx context.Context, exec bob.Executor, retrieved ChatConversationsCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountChatConversations(ctx, exec, mods...)
			},
		),
		ChatMessageExecutions: countThenLoadBuilder[Q](
			"ChatMessageExecutions",
			func(ctx context.Context, exec bob.Executor, retrieved ChatMessageExecutionsCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountChatMessageExecutions(ctx, exec, mods...)
			},
		),
		ConnectionAccesses: countThenLoadBuilder[Q](
			"ConnectionAccesses",
			func(ctx context.Context, exec bob.Executor, retrieved ConnectionAccessesCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountConnectionAccesses(ctx, exec, mods...)
			},
		),
		SchemaChunks: countThenLoadBuilder[Q](
			"SchemaChunks",
			func(ctx context.Context, exec bob.Executor, retrieved SchemaChunksCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountSchemaChunks(ctx, exec, mods...)
			},
		),
		SchemaSnapshots: countThenLoadBuilder[Q](
			"SchemaSnapshots",
			func(ctx context.Context, exec bob.Executor, retrieved SchemaSnapshotsCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountSchemaSnapshots(ctx, exec, mods...)
			},
		),
	}
}

